fun solve(value: Array<Long>, limit: Array<Long>): Long {
    val n = value.size
    val elements = (0 until n).sortedWith(compareByDescending({ value[it] }, { it }))
    val activeLimits = PriorityQueue<Long>(Comparator{ a, b -> a.compareTo(b) })
    val activeElements = mutableSetOf<Int>()
    var totalSum = 0L

    for (i in elements) {
        val currentActiveCount = activeElements.size
        if (currentActiveCount < limit[i]) {
            totalSum += value[i]
            activeElements.add(i)
            activeLimits.add(limit[i])
        }

        val currentActiveCountAfter = currentActiveCount + 1
        activeElements.forEach { j ->
            if (limit[j] <= currentActiveCountAfter) {
                activeElements.remove(j)
            }
        }
    }

    return totalSum
}
